import React, {useState} from "react";
import Chart from "./Chart";

const StatisticsTableClients = (props) => {
    let arrayEntriesClients = [];
    let count = 1;

    const getStatisticsOfClient = () =>{
        let mapRes = new Map();
        props.orders.map(order => {
            let temp = null;
            temp = order.username === undefined ? order.email : temp = order.username;
            if(!mapRes.has(temp)){
                mapRes.set(temp, {count: 1, totalPurchases: order.totalPrice});
            } else {
                let property = mapRes.get(temp);
                mapRes.set(temp, {count: property.count + 1, totalPurchases: property.totalPurchases + order.totalPrice});
            }
        })
        return mapRes;
    }
    const maxVisitedOfClient = new Map([...getStatisticsOfClient().entries()].sort((a, b) => b[1].count - a[1].count));


    let database = {labels: [], data: []}
    for (let entry of maxVisitedOfClient){
        arrayEntriesClients.push(entry);
       database.labels.push(entry[0]);
       database.data.push(entry[1].totalPurchases);
    }




    let itemProduct = arrayEntriesClients.map(entry => {
        return <React.Fragment key={entry[0]}>
            <tr key={entry[0]}>
                <td>{count++}</td>
                    <td>{entry[0]}</td>
                        <td>{entry[1].count}</td>
                            <td>₪{entry[1].totalPurchases.toFixed(2)}</td>
            </tr>
        </React.Fragment>
    })



    return <React.Fragment>
        <div>
            <div className="table-product_title">
                <span >Most visited clients:</span>
            </div>
            <table>
                <thead >
                <tr>
                    <th>#</th>
                    <th>Client name</th>
                    <th>Number of purchases</th>
                    <th>Total purchases</th>
                </tr>
                </thead>
                <tbody>
                {itemProduct}
                </tbody>
            </table>
            <Chart database={database}/>
        </div>
    </React.Fragment>
}
export default StatisticsTableClients;
